// src/services/incidentService.js
import {
  collection,
  addDoc,
  updateDoc,
  doc,
  onSnapshot,
  query,
  orderBy,
  where,
  getDocs,
  serverTimestamp,
  Timestamp
} from 'firebase/firestore';
import { db } from '../firebase/firebase';

const INCIDENTS_COL = 'incidents';
const STAFF_COL     = 'staff';

// ─────────────────────────────────────────────
// INCIDENT CRUD
// ─────────────────────────────────────────────

/**
 * Create a new incident in Firestore.
 * @param {{ type, location, mode }} data
 * @returns {Promise<string>} new incident id
 */
export async function createIncident({ type, location, mode = 'online' }) {
  const incident = {
    type,
    location,
    status:     'active',
    assignedTo: null,
    timestamp:  Date.now(),
    mode,
  };

  const docRef = await addDoc(collection(db, INCIDENTS_COL), incident);
  console.log('[incidentService] Created incident:', docRef.id);

  // Auto-assign nearest available staff after creating
  await autoAssignStaff(docRef.id, location);

  return docRef.id;
}

/**
 * Update incident status.
 * @param {string} incidentId
 * @param {'active'|'assigned'|'in_progress'|'resolved'} status
 */
export async function updateIncidentStatus(incidentId, status) {
  const ref = doc(db, INCIDENTS_COL, incidentId);
  await updateDoc(ref, { status });
  console.log(`[incidentService] Incident ${incidentId} → ${status}`);
}

/**
 * Assign a staff member to an incident.
 * @param {string} incidentId
 * @param {string} staffId
 */
export async function assignIncident(incidentId, staffId) {
  const incidentRef = doc(db, INCIDENTS_COL, incidentId);
  const staffRef    = doc(db, STAFF_COL, staffId);

  await updateDoc(incidentRef, { assignedTo: staffId, status: 'assigned' });
  await updateDoc(staffRef,    { available: false });
  console.log(`[incidentService] Incident ${incidentId} assigned to ${staffId}`);
}

/**
 * Mark staff as available again when incident resolved.
 * @param {string} incidentId
 * @param {string} staffId
 */
export async function resolveIncident(incidentId, staffId) {
  const incidentRef = doc(db, INCIDENTS_COL, incidentId);
  await updateDoc(incidentRef, { status: 'resolved' });

  if (staffId) {
    const staffRef = doc(db, STAFF_COL, staffId);
    await updateDoc(staffRef, { available: true });
  }
}

// ─────────────────────────────────────────────
// AUTO STAFF ASSIGNMENT
// ─────────────────────────────────────────────

/**
 * Find the nearest available staff member and assign them.
 * "Nearest" = same floor extracted from location string, fallback to any available.
 */
export async function autoAssignStaff(incidentId, location) {
  try {
    const staffSnap = await getDocs(
      query(collection(db, STAFF_COL), where('available', '==', true))
    );

    if (staffSnap.empty) {
      console.warn('[autoAssign] No available staff.');
      return;
    }

    const staffList = staffSnap.docs.map((d) => ({ id: d.id, ...d.data() }));

    // Extract floor number from location string (e.g. "Room 204" → floor "2")
    const floorMatch = location.match(/\d+/);
    const incidentFloor = floorMatch ? floorMatch[0][0] : null;

    // Prefer same floor, fallback to first available
    const match = incidentFloor
      ? staffList.find((s) => String(s.floor) === incidentFloor) || staffList[0]
      : staffList[0];

    await assignIncident(incidentId, match.id);
    console.log(`[autoAssign] Assigned ${match.name} (${match.id}) to incident ${incidentId}`);
  } catch (err) {
    console.error('[autoAssign] Error:', err);
  }
}

// ─────────────────────────────────────────────
// REAL-TIME LISTENERS
// ─────────────────────────────────────────────

/**
 * Subscribe to all incidents in real-time (for staff dashboard).
 * @param {function} callback - called with array of incidents on every change
 * @returns {function} unsubscribe
 */
export function subscribeToIncidents(callback) {
  const q = query(
    collection(db, INCIDENTS_COL),
    orderBy('timestamp', 'desc')
  );

  return onSnapshot(q, (snapshot) => {
    const incidents = snapshot.docs.map((d) => ({ id: d.id, ...d.data() }));
    callback(incidents);
  }, (err) => {
    console.error('[subscribeToIncidents] Error:', err);
  });
}

/**
 * Subscribe to active (non-resolved) incidents only.
 * @param {function} callback
 * @returns {function} unsubscribe
 */
export function subscribeToActiveIncidents(callback) {
  const q = query(
    collection(db, INCIDENTS_COL),
    where('status', '!=', 'resolved'),
    orderBy('status'),
    orderBy('timestamp', 'desc')
  );

  return onSnapshot(q, (snapshot) => {
    const incidents = snapshot.docs.map((d) => ({ id: d.id, ...d.data() }));
    callback(incidents);
  });
}

/**
 * Subscribe to a single incident (for status tracking).
 * @param {string} incidentId
 * @param {function} callback
 * @returns {function} unsubscribe
 */
export function subscribeToIncident(incidentId, callback) {
  return onSnapshot(doc(db, INCIDENTS_COL, incidentId), (snap) => {
    if (snap.exists()) callback({ id: snap.id, ...snap.data() });
  });
}

/**
 * Subscribe to all staff (for dashboard).
 * @param {function} callback
 * @returns {function} unsubscribe
 */
export function subscribeToStaff(callback) {
  return onSnapshot(collection(db, STAFF_COL), (snap) => {
    const staff = snap.docs.map((d) => ({ id: d.id, ...d.data() }));
    callback(staff);
  });
}

// ─────────────────────────────────────────────
// SEED DATA (run once for demo)
// ─────────────────────────────────────────────

/**
 * Seed demo staff into Firestore (call once during setup).
 */
export async function seedStaff() {
  const staffData = [
    { id: 'staff_01', name: 'John',   floor: '2', available: true },
    { id: 'staff_02', name: 'Maria',  floor: '3', available: true },
    { id: 'staff_03', name: 'Ravi',   floor: '1', available: true },
    { id: 'staff_04', name: 'Priya',  floor: '4', available: true },
  ];

  for (const staff of staffData) {
    const { id, ...data } = staff;
    await updateDoc(doc(db, STAFF_COL, id), data).catch(async () => {
      // doc doesn't exist yet — use setDoc
      const { setDoc } = await import('firebase/firestore');
      await setDoc(doc(db, STAFF_COL, id), data);
    });
  }
  console.log('[seedStaff] Staff seeded.');
}
