// src/hooks/useSOS.js
import { useState, useCallback } from 'react';
import { createIncident } from '../services/incidentService';
import { enqueue } from '../services/offlineQueue';
import { LORA_GATEWAY_URL } from '../utils/constants';

/**
 * useSOS — Smart SOS routing hook.
 *
 * Priority: online → LoRa (if enabled) → offline queue
 *
 * Returns:
 *   sendSOS(type, location, options) → Promise<{ success, mode, id? }>
 *   sending: boolean
 *   lastResult: { success, mode, id, error? } | null
 */
export function useSOS() {
  const [sending, setSending]       = useState(false);
  const [lastResult, setLastResult] = useState(null);

  const sendSOS = useCallback(async (type, location, options = {}) => {
    const { forceLoRa = false } = options;
    setSending(true);
    let result;

    try {
      const isOnline = navigator.onLine;

      // ── 1. ONLINE MODE ─────────────────────────
      if (isOnline && !forceLoRa) {
        try {
          const id = await createIncident({ type, location, mode: 'online' });
          result = { success: true, mode: 'online', id };
          console.log('[useSOS] Sent via Firebase (online)');
        } catch (firebaseErr) {
          console.warn('[useSOS] Firebase failed, trying LoRa fallback...', firebaseErr);
          result = await sendViaLoRa(type, location);
        }

      // ── 2. FORCED LORA MODE ────────────────────
      } else if (forceLoRa) {
        result = await sendViaLoRa(type, location);

      // ── 3. OFFLINE MODE ────────────────────────
      } else {
        const queueId = enqueue({ type, location, mode: 'offline' });
        result = { success: true, mode: 'offline', id: queueId };
        console.log('[useSOS] Queued offline:', queueId);
      }
    } catch (err) {
      console.error('[useSOS] All methods failed:', err);
      // Last resort: queue it
      try {
        const queueId = enqueue({ type, location, mode: 'offline' });
        result = { success: true, mode: 'offline', id: queueId };
      } catch {
        result = { success: false, mode: 'error', error: err.message };
      }
    }

    setLastResult(result);
    setSending(false);
    return result;
  }, []);

  return { sendSOS, sending, lastResult };
}

// ─────────────────────────────────────────────
// LoRa Gateway Relay
// ─────────────────────────────────────────────

async function sendViaLoRa(type, location) {
  try {
    const res = await fetch(`${LORA_GATEWAY_URL}/send`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ type, location, mode: 'lora', timestamp: Date.now() }),
    });

    if (!res.ok) throw new Error(`LoRa gateway responded with ${res.status}`);

    const data = await res.json();
    console.log('[useSOS] Sent via LoRa gateway:', data);
    return { success: true, mode: 'lora', id: data.incidentId || data.id };
  } catch (loraErr) {
    console.warn('[useSOS] LoRa failed, queuing offline:', loraErr);
    const queueId = enqueue({ type, location, mode: 'lora_fallback' });
    return { success: true, mode: 'offline', id: queueId };
  }
}
