// src/screens/SOSScreen.jsx
import React, { useState, useRef } from 'react';
import { useSOS } from '../hooks/useSOS';
import { SOS_TYPES, MODE_CONFIG } from '../utils/constants';

const LOCATIONS = [
  'Room 101', 'Room 202', 'Room 204', 'Room 305', 'Room 410',
  'Lobby', 'Cafeteria', 'Parking Lot', 'Stairwell A', 'Stairwell B',
  'Roof', 'Basement', 'Server Room', 'Conference Hall',
];

export default function SOSScreen({ isOnline, showToast }) {
  const [selectedType,     setSelectedType]     = useState(null);
  const [selectedLocation, setSelectedLocation] = useState('');
  const [customLocation,   setCustomLocation]   = useState('');
  const [loraMode,         setLoraMode]         = useState(false);
  const [confirmed,        setConfirmed]        = useState(false);
  const [lastSent,         setLastSent]         = useState(null);
  const holdTimer = useRef(null);
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef(null);
  const HOLD_DURATION = 1500; // ms

  const { sendSOS, sending } = useSOS();

  const location = customLocation.trim() || selectedLocation;

  // ── Hold-to-send SOS ───────────────────────
  const startHold = () => {
    if (!selectedType || !location || sending) return;
    setHoldProgress(0);

    const startTime = Date.now();
    holdInterval.current = setInterval(() => {
      const elapsed  = Date.now() - startTime;
      const progress = Math.min((elapsed / HOLD_DURATION) * 100, 100);
      setHoldProgress(progress);
      if (progress >= 100) {
        clearInterval(holdInterval.current);
        triggerSOS();
      }
    }, 30);
  };

  const cancelHold = () => {
    clearInterval(holdInterval.current);
    clearTimeout(holdTimer.current);
    setHoldProgress(0);
  };

  const triggerSOS = async () => {
    setHoldProgress(0);
    const result = await sendSOS(selectedType, location, { forceLoRa: loraMode });

    if (result.success) {
      const modeInfo = MODE_CONFIG[result.mode] || MODE_CONFIG.online;
      showToast(`SOS sent via ${modeInfo.label}`, 'success');
      setLastSent({ ...result, type: selectedType, location, sentAt: Date.now() });
      setConfirmed(true);
      setTimeout(() => setConfirmed(false), 4000);
    } else {
      showToast('Failed to send SOS. Try again.', 'error');
    }
  };

  const typeInfo   = selectedType ? SOS_TYPES[selectedType] : null;
  const canSend    = !!selectedType && !!location && !sending;

  return (
    <div style={{
      padding:        '24px 20px',
      paddingBottom:  'calc(var(--nav-height) + 24px)',
      minHeight:      '100dvh',
      display:        'flex',
      flexDirection:  'column',
      gap:            '24px',
      animation:      'fade-in 0.4s ease',
    }}>

      {/* Header */}
      <div>
        <div style={{
          display:     'flex',
          alignItems:  'baseline',
          gap:         '10px',
          marginBottom:'4px',
        }}>
          <h1 style={{ fontSize: '28px', letterSpacing: '-0.02em' }}>
            RESPOND
          </h1>
          <span style={{
            fontSize:   '11px',
            fontFamily: 'var(--font-mono)',
            color:      isOnline ? '#00ff88' : '#ffc300',
            background: isOnline ? 'rgba(0,255,136,0.1)' : 'rgba(255,195,0,0.1)',
            border:     `1px solid ${isOnline ? 'rgba(0,255,136,0.25)' : 'rgba(255,195,0,0.25)'}`,
            padding:    '3px 8px',
            borderRadius:'4px',
            display:    'flex',
            alignItems: 'center',
            gap:        '5px',
          }}>
            <span style={{
              width:'6px', height:'6px', borderRadius:'50%',
              background: isOnline ? '#00ff88' : '#ffc300',
              display:'inline-block',
              animation: 'pulse-dot 2s ease infinite',
            }}/>
            {isOnline ? 'ONLINE' : 'OFFLINE'}
          </span>
        </div>
        <p style={{ color:'var(--text-secondary)', fontSize:'14px' }}>
          Emergency crisis response system
        </p>
      </div>

      {/* SOS Type Selection */}
      <div>
        <p style={{
          fontSize:      '11px',
          fontFamily:    'var(--font-mono)',
          color:         'var(--text-muted)',
          letterSpacing: '0.12em',
          marginBottom:  '12px',
        }}>
          SELECT INCIDENT TYPE
        </p>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'10px' }}>
          {Object.entries(SOS_TYPES).map(([key, info]) => {
            const isSelected = selectedType === key;
            return (
              <button
                key={key}
                onClick={() => setSelectedType(isSelected ? null : key)}
                style={{
                  background:   isSelected ? `${info.bg}` : 'var(--bg-surface)',
                  border:       `1px solid ${isSelected ? info.color : 'var(--border)'}`,
                  borderRadius: 'var(--radius-lg)',
                  padding:      '16px 8px',
                  display:      'flex',
                  flexDirection:'column',
                  alignItems:   'center',
                  gap:          '8px',
                  transition:   'all 0.2s ease',
                  boxShadow:    isSelected ? `0 0 20px ${info.color}33` : 'none',
                  transform:    isSelected ? 'scale(1.03)' : 'scale(1)',
                }}
              >
                <span style={{ fontSize:'28px', lineHeight:1 }}>{info.emoji}</span>
                <span style={{
                  fontSize:   '12px',
                  fontWeight: 700,
                  color:      isSelected ? info.color : 'var(--text-secondary)',
                  letterSpacing:'0.05em',
                }}>
                  {info.label.toUpperCase()}
                </span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Location Selection */}
      <div>
        <p style={{
          fontSize:      '11px',
          fontFamily:    'var(--font-mono)',
          color:         'var(--text-muted)',
          letterSpacing: '0.12em',
          marginBottom:  '12px',
        }}>
          YOUR LOCATION
        </p>

        {/* Preset locations */}
        <div style={{
          display:   'flex',
          flexWrap:  'wrap',
          gap:       '8px',
          marginBottom:'12px',
        }}>
          {LOCATIONS.map((loc) => {
            const isSel = selectedLocation === loc;
            return (
              <button
                key={loc}
                onClick={() => { setSelectedLocation(isSel ? '' : loc); setCustomLocation(''); }}
                style={{
                  background:   isSel ? 'rgba(0,194,255,0.12)' : 'var(--bg-surface)',
                  border:       `1px solid ${isSel ? 'rgba(0,194,255,0.4)' : 'var(--border)'}`,
                  borderRadius: 'var(--radius-full)',
                  padding:      '6px 14px',
                  fontSize:     '13px',
                  color:        isSel ? '#00c2ff' : 'var(--text-secondary)',
                  fontWeight:   isSel ? 700 : 500,
                  transition:   'all 0.15s ease',
                }}
              >
                {loc}
              </button>
            );
          })}
        </div>

        {/* Custom location input */}
        <input
          type="text"
          placeholder="Or type a custom location..."
          value={customLocation}
          onChange={(e) => { setCustomLocation(e.target.value); setSelectedLocation(''); }}
          style={{
            width:        '100%',
            background:   'var(--bg-surface)',
            border:       `1px solid ${customLocation ? 'rgba(0,194,255,0.3)' : 'var(--border)'}`,
            borderRadius: 'var(--radius-md)',
            padding:      '12px 16px',
            fontSize:     '14px',
            color:        'var(--text-primary)',
            fontFamily:   'var(--font-display)',
            outline:      'none',
            transition:   'border-color 0.2s',
          }}
        />
      </div>

      {/* LoRa Toggle */}
      <div style={{
        display:     'flex',
        alignItems:  'center',
        justifyContent:'space-between',
        background:  'var(--bg-surface)',
        border:      '1px solid var(--border)',
        borderRadius:'var(--radius-md)',
        padding:     '14px 16px',
      }}>
        <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
          <span style={{ fontSize:'20px' }}>📡</span>
          <div>
            <p style={{ fontSize:'14px', fontWeight:700, marginBottom:'2px' }}>LoRa Mode</p>
            <p style={{ fontSize:'12px', color:'var(--text-muted)' }}>
              Use radio relay when WiFi is unavailable
            </p>
          </div>
        </div>
        <button
          onClick={() => setLoraMode(!loraMode)}
          style={{
            width:      '48px',
            height:     '28px',
            borderRadius:'14px',
            background: loraMode ? '#c084fc' : 'var(--bg-highlight)',
            position:   'relative',
            transition: 'background 0.2s ease',
            flexShrink: 0,
            boxShadow:  loraMode ? '0 0 12px rgba(192,132,252,0.5)' : 'none',
          }}
        >
          <span style={{
            position:   'absolute',
            top:        '3px',
            left:       loraMode ? '23px' : '3px',
            width:      '22px',
            height:     '22px',
            borderRadius:'50%',
            background: '#fff',
            transition: 'left 0.2s cubic-bezier(0.34,1.56,0.64,1)',
            boxShadow:  '0 1px 4px rgba(0,0,0,0.4)',
          }} />
        </button>
      </div>

      {/* SOS Button */}
      <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:'12px' }}>

        {/* Hold-to-send button */}
        <div style={{ position:'relative', display:'inline-flex', alignItems:'center', justifyContent:'center' }}>

          {/* Pulse rings (when can send) */}
          {canSend && !sending && (
            <>
              {[0, 300, 600].map((delay) => (
                <span key={delay} style={{
                  position:   'absolute',
                  width:      '160px',
                  height:     '160px',
                  borderRadius:'50%',
                  border:     `2px solid ${typeInfo?.color || '#ff4500'}`,
                  opacity:    0,
                  animation:  `pulse-ring 2s ${delay}ms ease-out infinite`,
                }} />
              ))}
            </>
          )}

          {/* Main SOS button */}
          <button
            onPointerDown={startHold}
            onPointerUp={cancelHold}
            onPointerLeave={cancelHold}
            disabled={!canSend}
            style={{
              width:        '140px',
              height:       '140px',
              borderRadius: '50%',
              background:   canSend
                ? `conic-gradient(${typeInfo?.color || '#ff4500'} ${holdProgress * 3.6}deg, var(--bg-raised) 0deg)`
                : 'var(--bg-surface)',
              border:       `3px solid ${canSend ? (typeInfo?.color || '#ff4500') : 'var(--border)'}`,
              display:      'flex',
              flexDirection:'column',
              alignItems:   'center',
              justifyContent:'center',
              gap:          '8px',
              cursor:       canSend ? 'pointer' : 'not-allowed',
              position:     'relative',
              transition:   'transform 0.15s, box-shadow 0.15s',
              boxShadow:    canSend ? `0 0 ${holdProgress > 0 ? '40px' : '20px'} ${typeInfo?.color || '#ff4500'}44` : 'none',
            }}
          >
            {/* Inner circle overlay for conic gradient */}
            <span style={{
              position:     'absolute',
              inset:        '8px',
              borderRadius: '50%',
              background:   sending ? 'var(--bg-surface)' : (canSend ? typeInfo?.bg || 'var(--bg-raised)' : 'var(--bg-surface)'),
              display:      'flex',
              flexDirection:'column',
              alignItems:   'center',
              justifyContent:'center',
              gap:          '4px',
            }}>
              {sending ? (
                <span style={{
                  fontSize:  '30px',
                  animation: 'spin 1s linear infinite',
                }}>⟳</span>
              ) : confirmed ? (
                <span style={{ fontSize:'36px' }}>✓</span>
              ) : (
                <>
                  <span style={{ fontSize:'32px', lineHeight:1 }}>
                    {typeInfo?.emoji || '🆘'}
                  </span>
                  <span style={{
                    fontSize:   '11px',
                    fontWeight: 800,
                    color:      canSend ? typeInfo?.color || '#ff4500' : 'var(--text-muted)',
                    letterSpacing:'0.1em',
                  }}>
                    {holdProgress > 0 ? `${Math.round(holdProgress)}%` : 'HOLD'}
                  </span>
                </>
              )}
            </span>
          </button>
        </div>

        <p style={{
          fontSize:   '13px',
          color:      'var(--text-muted)',
          textAlign:  'center',
          fontFamily: 'var(--font-mono)',
        }}>
          {!selectedType    ? 'Select an incident type'
           : !location      ? 'Enter your location'
           : sending        ? 'Sending SOS...'
           : confirmed      ? '✓ SOS Dispatched!'
           : 'Hold button to send SOS'}
        </p>

        {/* Last sent info */}
        {lastSent && (
          <div style={{
            background:   'var(--bg-surface)',
            border:       '1px solid var(--border)',
            borderRadius: 'var(--radius-md)',
            padding:      '12px 16px',
            width:        '100%',
            animation:    'slide-up 0.3s ease',
          }}>
            <p style={{
              fontSize:   '11px',
              fontFamily: 'var(--font-mono)',
              color:      'var(--text-muted)',
              marginBottom:'6px',
              letterSpacing:'0.08em',
            }}>
              LAST SENT
            </p>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div>
                <p style={{ fontSize:'14px', fontWeight:700, marginBottom:'2px' }}>
                  {SOS_TYPES[lastSent.type]?.emoji} {SOS_TYPES[lastSent.type]?.label} — {lastSent.location}
                </p>
                <p style={{ fontSize:'12px', color:'var(--text-muted)', fontFamily:'var(--font-mono)' }}>
                  {new Date(lastSent.sentAt).toLocaleTimeString()}
                </p>
              </div>
              <span style={{
                fontSize:     '11px',
                fontFamily:   'var(--font-mono)',
                color:        MODE_CONFIG[lastSent.mode]?.color || '#00ff88',
                background:   `${MODE_CONFIG[lastSent.mode]?.color || '#00ff88'}18`,
                border:       `1px solid ${MODE_CONFIG[lastSent.mode]?.color || '#00ff88'}33`,
                padding:      '4px 10px',
                borderRadius: '6px',
              }}>
                {MODE_CONFIG[lastSent.mode]?.icon} {MODE_CONFIG[lastSent.mode]?.label}
              </span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
