// src/services/offlineQueue.js
import { createIncident } from './incidentService';

const QUEUE_KEY = 'respond_offline_queue';

// ─────────────────────────────────────────────
// QUEUE MANAGEMENT
// ─────────────────────────────────────────────

/** Read the full queue from localStorage */
export function getQueue() {
  try {
    return JSON.parse(localStorage.getItem(QUEUE_KEY) || '[]');
  } catch {
    return [];
  }
}

/** Save queue to localStorage */
function saveQueue(queue) {
  localStorage.setItem(QUEUE_KEY, JSON.stringify(queue));
}

/**
 * Add an incident to the offline queue.
 * @param {{ type, location, mode }} incident
 * @returns {string} local queue id
 */
export function enqueue(incident) {
  const queue = getQueue();
  const queueId = `offline_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
  const item = {
    queueId,
    ...incident,
    mode: 'offline',
    timestamp: Date.now(),
    synced: false,
  };
  queue.push(item);
  saveQueue(queue);
  console.log('[offlineQueue] Enqueued:', queueId);
  return queueId;
}

/**
 * Remove a successfully synced item from the queue.
 * @param {string} queueId
 */
export function dequeue(queueId) {
  const queue = getQueue().filter((item) => item.queueId !== queueId);
  saveQueue(queue);
}

/** Get count of unsynced items */
export function getPendingCount() {
  return getQueue().filter((item) => !item.synced).length;
}

// ─────────────────────────────────────────────
// SYNC
// ─────────────────────────────────────────────

let syncInProgress = false;

/**
 * Attempt to sync all queued incidents to Firestore.
 * Safe to call repeatedly — will skip if already running.
 * @param {function} onProgress - called with { synced, failed, total }
 */
export async function syncQueue(onProgress) {
  if (syncInProgress) return;
  syncInProgress = true;

  const queue = getQueue().filter((item) => !item.synced);
  if (queue.length === 0) {
    syncInProgress = false;
    return;
  }

  console.log(`[offlineQueue] Syncing ${queue.length} queued incidents...`);
  let synced = 0;
  let failed = 0;

  for (const item of queue) {
    try {
      await createIncident({
        type:     item.type,
        location: item.location,
        mode:     item.mode || 'offline',
      });
      dequeue(item.queueId);
      synced++;
      console.log(`[offlineQueue] Synced: ${item.queueId}`);
    } catch (err) {
      failed++;
      console.error(`[offlineQueue] Failed to sync ${item.queueId}:`, err);
    }

    if (onProgress) {
      onProgress({ synced, failed, total: queue.length });
    }
  }

  syncInProgress = false;
  console.log(`[offlineQueue] Sync complete. ${synced} synced, ${failed} failed.`);
}

// ─────────────────────────────────────────────
// AUTO-SYNC ON RECONNECT
// ─────────────────────────────────────────────

/**
 * Register window online/offline listeners for automatic sync.
 * @param {function} onStatusChange - called with { online: boolean }
 * @param {function} onSyncProgress - called with sync progress
 * @returns {function} cleanup function
 */
export function registerNetworkListeners(onStatusChange, onSyncProgress) {
  const handleOnline = () => {
    console.log('[offlineQueue] Network restored. Auto-syncing...');
    onStatusChange?.({ online: true });
    syncQueue(onSyncProgress);
  };

  const handleOffline = () => {
    console.log('[offlineQueue] Network lost.');
    onStatusChange?.({ online: false });
  };

  window.addEventListener('online',  handleOnline);
  window.addEventListener('offline', handleOffline);

  return () => {
    window.removeEventListener('online',  handleOnline);
    window.removeEventListener('offline', handleOffline);
  };
}
